using CustomInspector;
using Mirror;
using PlayerBehaviour;
using System;
using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class Shooting : NetworkEnabled
{
    public Shooting(Activation activation) : base(activation) { }

    [SerializeField, SelfFill] protected CarData _playerData;

    [SerializeField, ForceFill] GameObject bulletTrailPrefab;
    [SerializeField, ForceFill] GameObject confettiPrefab;
    static ParticleSystem confettiInstance;

    [ShowIf(StaticConditions.IsPlaying), ReadOnly]
    public WeaponInfos.WeaponStats weaponStats = WeaponInfos.WeaponStats.DefaultValues();

    [Server]
    protected void SvrHitOtherPlayer(uint hittet)
    {
        CarInitialize otherPlayer = CarInitialize.Players[hittet];
        var health = otherPlayer.GetComponent<PlayerHealth>();
        float distance = (int)(otherPlayer.transform.position - this.transform.position).magnitude;
        int damageLoss = (int)(distance * weaponStats.damageFallOff);
        health.TakeDamage(Math.Max(1, weaponStats.damage - damageLoss), out bool died);

        if (died)
        {
            //on clients he doesnt exist anymore so we need to tell his name
            RpcDisplayKill(otherPlayer.Username);
        }
    }
    [ClientRpc]
    void RpcDisplayKill(string killed)
    {
        string thisName = _playerData.Username;
        KillFeed.DisplayKill(thisName, killed);
    }



    [Server]
    protected void SvrShootEffect(Vector3 start, Vector3 end, Vector3 normal) => RpcShootEffect(start, end, normal);
    [ClientRpc]
    void RpcShootEffect(Vector3 start, Vector3 end, Vector3 normal)
    {
        // sound
        _playerData.AudioSource.Play();
        // Bullet trail
        GameObject bulletTrail = Instantiate(bulletTrailPrefab);
        var lr = bulletTrail.GetComponent<BulletTrail>();
        lr.Initialize(start, end);
        //muzzle flash
        _playerData.TurretInfo.PlayShootEffects();

        //confetti (where it hits)
        if (confettiInstance == null)
            confettiInstance = Instantiate(confettiPrefab).GetComponent<ParticleSystem>();

        confettiInstance.transform.SetPositionAndRotation(end, Quaternion.LookRotation(normal));
        confettiInstance.Play();
    }

}

